import React, { useState, useEffect } from 'react';

const MortgageValues = ({amount, term, interest, setAmount, setTerm, setInterest}) => {
  
  useEffect(()=> {
    console.log(amount)
  })
  
    return(
        <div className='card-header border-top container d-flex justify-content-between'>
          <div className='d-flex'>Mortgage amount: <input type="text" name="amount" id="amount" value={amount?amount:250000} className="form-control ml-2" onChange={e=>setAmount(e.target.value)} /></div>
          <div className='d-flex'>Mortgage term: <input type="text" name="term" id="term" value={term?term:25} className="form-control ml-2" onChange={e=>setTerm(e.target.value)}  /></div>
          <div className='d-flex'>Interest rate: <input type="text" name="interest" id="interest" value={interest?interest:3} className="form-control ml-2" onChange={e=>setInterest(e.target.value)} /></div>
        </div>
     )
   }
   
   export default MortgageValues;